using System;
using System.Net.Http;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;

namespace WebhookProxy
{
    public class ProxyController : ControllerBase
    {
        private readonly HttpClient _httpClient;

        public ProxyController(IHttpClientFactory httpClientFactory)
        {
            _httpClient = httpClientFactory.CreateClient();
        }

        [HttpPost]
        public async Task<IActionResult> Post([FromBody] string url)
        {
            if (string.IsNullOrEmpty(url))
            {
                return BadRequest("Invalid URL");
            }

            try
            {
                var response = await _httpClient.PostAsync(url, Request.Body);
                return Ok(response.Content.ReadAsStringAsync().Result);
            }
            catch (Exception ex)
            {
                return StatusCode((int)HttpStatusCode.InternalServerError, $"An error occurred while forwarding the request: {ex.Message}");
            }
        }
    }
}